/**
 * Custom Image Node for Lexical Editor
 * Supports image upload, resize, alt text, and delete
 */

import React, { useState } from 'react';
import { DecoratorNode } from 'lexical';
import { useLexicalComposerContext } from '@lexical/react/LexicalComposerContext';
import { indexedDBService } from '../../services/indexedDB';
import type {
  LexicalNode,
  NodeKey,
  SerializedLexicalNode,
  Spread,
  EditorConfig,
} from 'lexical';

export interface ImagePayload {
  altText: string;
  height?: number;
  maxWidth?: number;
  src: string;
  width?: number;
  imageId?: string;
  key?: NodeKey;
}

export type SerializedImageNode = Spread<
  {
    altText: string;
    height?: number;
    maxWidth: number;
    src: string;
    width?: number;
    imageId?: string;
  },
  SerializedLexicalNode
>;

export class ImageNode extends DecoratorNode<React.ReactElement> {
  __src: string;
  __altText: string;
  __width: 'inherit' | number;
  __height: 'inherit' | number;
  __maxWidth: number;
  __imageId: string;

  static getType(): string {
    return 'image';
  }

  static clone(node: ImageNode): ImageNode {
    return new ImageNode(
      node.__src,
      node.__altText,
      node.__maxWidth,
      node.__width,
      node.__height,
      node.__imageId,
      node.__key
    );
  }

  static importJSON(serializedNode: SerializedImageNode): ImageNode {
    const { altText, height, width, maxWidth, src, imageId } = serializedNode;
    const node = $createImageNode({
      altText,
      height,
      maxWidth,
      src,
      width,
      imageId,
    });
    return node;
  }

  exportJSON(): SerializedImageNode {
    return {
      altText: this.getAltText(),
      height: this.__height === 'inherit' ? 0 : this.__height,
      maxWidth: this.__maxWidth,
      src: this.getSrc(),
      type: 'image',
      version: 1,
      width: this.__width === 'inherit' ? 0 : this.__width,
      imageId: this.__imageId,
    };
  }

  constructor(
    src: string,
    altText: string,
    maxWidth: number,
    width?: 'inherit' | number,
    height?: 'inherit' | number,
    imageId?: string,
    key?: NodeKey
  ) {
    super(key);
    this.__src = src;
    this.__altText = altText;
    this.__maxWidth = maxWidth;
    this.__width = width || 'inherit';
    this.__height = height || 'inherit';
    this.__imageId = imageId || '';
  }

  createDOM(config: EditorConfig): HTMLElement {
    const span = document.createElement('span');
    const theme = config.theme;
    const className = theme.image;
    if (className !== undefined) {
      span.className = className;
    }
    return span;
  }

  updateDOM(): false {
    return false;
  }

  getSrc(): string {
    return this.__src;
  }

  getAltText(): string {
    return this.__altText;
  }

  setAltText(altText: string): void {
    const writable = this.getWritable();
    writable.__altText = altText;
  }

  setWidth(width: number): void {
    const writable = this.getWritable();
    writable.__width = width;
  }

  decorate(): React.ReactElement {
    return (
      <ImageComponent
        src={this.__src}
        altText={this.__altText}
        width={this.__width}
        height={this.__height}
        maxWidth={this.__maxWidth}
        imageId={this.__imageId}
        nodeKey={this.__key}
      />
    );
  }
}

/**
 * Image Component with Controls
 * Handles resize, alt text editing, and delete
 */
function ImageComponent({
  src,
  altText,
  width,
  height,
  maxWidth,
  imageId,
  nodeKey,
}: {
  src: string;
  altText: string;
  width: 'inherit' | number;
  height: 'inherit' | number;
  maxWidth: number;
  imageId: string;
  nodeKey: NodeKey;
}) {
  const [editor] = useLexicalComposerContext();
  const [isHovered, setIsHovered] = useState(false);
  const [showAltEditor, setShowAltEditor] = useState(false);
  const [editedAltText, setEditedAltText] = useState(altText);

  const handleDelete = async () => {
    if (!confirm('Delete this image?')) return;

    try {
      // Delete from IndexedDB
      if (imageId) {
        await indexedDBService.deleteImage(imageId);
      }

      // Revoke blob URL
      URL.revokeObjectURL(src);

      // Remove node from editor
      editor.update(() => {
        const node = editor.getEditorState().read(() => {
          return editor.getEditorState()._nodeMap.get(nodeKey);
        });
        if (node) {
          node.remove();
        }
      });

      console.log(`✅ Deleted image: ${imageId}`);
    } catch (error) {
      console.error('Failed to delete image:', error);
    }
  };

  const handleSaveAltText = () => {
    editor.update(() => {
      const node = editor.getEditorState().read(() => {
        return editor.getEditorState()._nodeMap.get(nodeKey);
      });
      if (node && node instanceof ImageNode) {
        node.setAltText(editedAltText);
      }
    });
    setShowAltEditor(false);
    console.log(`✅ Updated alt text: "${editedAltText}"`);
  };

  return (
    <div
      className="inline-block my-4 group"
      onMouseEnter={() => setIsHovered(true)}
      onMouseLeave={() => setIsHovered(false)}
    >
      {/* Resizable container */}
      <div
        className="resize overflow-auto inline-block rounded-lg border-2 border-transparent hover:border-accent-blue/30 transition-all duration-200"
        style={{
          maxWidth: maxWidth,
          resize: 'both',
        }}
      >
        <img
          src={src}
          alt={altText}
          style={{
            width: width === 'inherit' ? '100%' : width,
            height: height === 'inherit' ? 'auto' : height,
            display: 'block',
          }}
          className="max-w-full h-auto rounded-lg pointer-events-none"
          draggable={false}
        />
      </div>

      {/* Hover controls - positioned below image with proper spacing */}
      {isHovered && !showAltEditor && (
        <div className="flex items-center justify-center gap-2 mt-2 opacity-0 group-hover:opacity-100 transition-opacity duration-200">
          <button
            onClick={() => setShowAltEditor(true)}
            className="px-3 py-1 bg-surface-light dark:bg-surface-dark border border-border-light dark:border-border-dark rounded-lg text-sm text-text-light-primary dark:text-text-dark-primary hover:bg-accent-blue hover:text-white transition-colors shadow-elevated"
            title="Edit alt text"
          >
            ✏️ Alt text
          </button>
          <button
            onClick={handleDelete}
            className="px-3 py-1 bg-surface-light dark:bg-surface-dark border border-border-light dark:border-border-dark rounded-lg text-sm text-text-light-primary dark:text-text-dark-primary hover:bg-red-500 hover:text-white transition-colors shadow-elevated"
            title="Delete image"
          >
            🗑️ Delete
          </button>
        </div>
      )}

      {/* Alt text editor modal */}
      {showAltEditor && (
        <div className="fixed inset-0 z-50 flex items-center justify-center bg-black/50" onClick={() => setShowAltEditor(false)}>
          <div className="bg-surface-light dark:bg-surface-dark rounded-lg shadow-elevated p-6 max-w-md w-full mx-4" onClick={(e) => e.stopPropagation()}>
            <h3 className="text-lg font-semibold text-text-light-primary dark:text-text-dark-primary mb-4">
              Edit Alt Text
            </h3>
            <textarea
              value={editedAltText}
              onChange={(e) => setEditedAltText(e.target.value)}
              className="w-full h-24 px-3 py-2 bg-surface-light-elevated dark:bg-surface-dark-elevated border border-border-light dark:border-border-dark rounded-lg text-text-light-primary dark:text-text-dark-primary resize-none focus:outline-none focus:ring-2 focus:ring-accent-blue"
              placeholder="Describe this image for screen readers..."
              autoFocus
            />
            <div className="flex items-center justify-end gap-2 mt-4">
              <button
                onClick={() => setShowAltEditor(false)}
                className="px-4 py-2 text-sm text-text-light-secondary dark:text-text-dark-secondary hover:text-text-light-primary dark:hover:text-text-dark-primary transition-colors"
              >
                Cancel
              </button>
              <button
                onClick={handleSaveAltText}
                className="px-4 py-2 bg-accent-blue text-white rounded-lg text-sm hover:bg-accent-blue-hover transition-colors"
              >
                Save
              </button>
            </div>
          </div>
        </div>
      )}
    </div>
  );
}

export function $createImageNode({
  altText,
  height,
  maxWidth = 800,
  src,
  width,
  imageId,
  key,
}: ImagePayload): ImageNode {
  return new ImageNode(src, altText, maxWidth, width, height, imageId, key);
}

export function $isImageNode(
  node: LexicalNode | null | undefined
): node is ImageNode {
  return node instanceof ImageNode;
}

import React from 'react';
import { useAutomationStore } from '../../stores/useAutomationStore';

export const AutomationsList: React.FC = () => {
  const { rules, toggleRule, deleteRule } = useAutomationStore();

  if (rules.length === 0) {
    return (
      <div className="text-center py-12">
        <p className="text-text-light-secondary dark:text-text-dark-secondary mb-4">
          No automation rules yet
        </p>
        <p className="text-sm text-text-light-secondary dark:text-text-dark-secondary">
          Create your first automation to automate repetitive tasks
        </p>
      </div>
    );
  }

  return (
    <div className="space-y-3">
      {rules.map((rule) => (
        <div
          key={rule.id}
          className="p-4 bg-surface-light-elevated dark:bg-surface-dark-elevated rounded-lg border border-border-light dark:border-border-dark"
        >
          <div className="flex items-start justify-between gap-4">
            <div className="flex-1">
              <div className="flex items-center gap-2 mb-2">
                <h3 className="font-medium text-text-light-primary dark:text-text-dark-primary">
                  {rule.name}
                </h3>
                {rule.enabled ? (
                  <span className="text-xs px-2 py-0.5 rounded bg-status-success-bg text-status-success-text">
                    Enabled
                  </span>
                ) : (
                  <span className="text-xs px-2 py-0.5 rounded bg-neutral-200 dark:bg-neutral-700 text-text-light-secondary dark:text-text-dark-secondary">
                    Disabled
                  </span>
                )}
              </div>

              {rule.description && (
                <p className="text-sm text-text-light-secondary dark:text-text-dark-secondary mb-3">
                  {rule.description}
                </p>
              )}

              <div className="text-xs text-text-light-secondary dark:text-text-dark-secondary space-y-1">
                <div>
                  <span className="font-medium">Trigger:</span> {rule.trigger.type.replace('.', ' → ')}
                </div>
                {rule.conditions && rule.conditions.length > 0 && (
                  <div>
                    <span className="font-medium">Conditions:</span> {rule.conditions.length} condition(s)
                  </div>
                )}
                <div>
                  <span className="font-medium">Actions:</span> {rule.actions.length} action(s)
                </div>
                {rule.runCount > 0 && (
                  <div>
                    <span className="font-medium">Runs:</span> {rule.runCount}
                    {rule.lastRun && ` (last: ${new Date(rule.lastRun).toLocaleDateString()})`}
                  </div>
                )}
              </div>
            </div>

            <div className="flex items-center gap-2">
              <button
                onClick={() => toggleRule(rule.id)}
                className={`px-3 py-1.5 text-sm rounded transition-colors ${
                  rule.enabled
                    ? 'bg-status-warning-bg text-status-warning-text hover:bg-status-warning-bg/80'
                    : 'bg-status-success-bg text-status-success-text hover:bg-status-success-bg/80'
                }`}
              >
                {rule.enabled ? 'Disable' : 'Enable'}
              </button>
              <button
                onClick={() => {
                  if (confirm(`Delete automation "${rule.name}"?`)) {
                    deleteRule(rule.id);
                  }
                }}
                className="px-3 py-1.5 text-sm rounded bg-status-error-bg text-status-error-text hover:bg-status-error-bg/80 transition-colors"
              >
                Delete
              </button>
            </div>
          </div>
        </div>
      ))}
    </div>
  );
};

