    76→
    77→  const toggleExpand = useCallback((id: string) => {
    78→    setExpandedIds((prev) => {
    79→      const next = new Set(prev);
    80→      if (next.has(id)) {
    81→        next.delete(id);
    82→      } else {
    83→        next.add(id);
    84→      }
    85→      return next;
    86→    });
    87→  }, []);
    88→
    89→  const handleCreate = useCallback(() => {
    90→    setIsCreating(true);
    91→    setEditingId(null);
    92→    setFormData(defaultFormData);
    93→  }, []);
    94→
    95→  const handleEdit = useCallback((project: ProjectContext) => {
    96→    setEditingId(project.id);
    97→    setIsCreating(false);
    98→    setFormData({
    99→      name: project.name,
   100→      color: project.color,
   101→      icon: project.icon || '',
   102→      parentId: project.parentId,
   103→      description: project.description || '',
   104→    });
   105→  }, []);
   106→
   107→  const handleCancel = useCallback(() => {
   108→    setIsCreating(false);
