   179→
   180→    const handleDragLeave = (e: DragEvent) => {
   181→      e.preventDefault();
   182→      e.stopPropagation();
   183→      // Only hide if leaving the editor entirely
   184→      if (e.target === editorElement) {
   185→        setIsDragging(false);
   186→      }
   187→    };
   188→
   189→    const handleDrop = async (e: DragEvent) => {
   190→      e.preventDefault();
   191→      e.stopPropagation();
   192→      setIsDragging(false);
   193→
   194→      const files = Array.from(e.dataTransfer?.files || []);
   195→      const imageFiles = files.filter(file => file.type.startsWith('image/'));
   196→
   197→      for (const file of imageFiles) {
   198→        await uploadImage(file);
   199→      }
   200→    };
   201→
   202→    // Paste handler
   203→    const handlePaste = async (e: ClipboardEvent) => {
   204→      const items = Array.from(e.clipboardData?.items || []);
   205→      const imageItems = items.filter(item => item.type.startsWith('image/'));
   206→
   207→      if (imageItems.length > 0) {
   208→        e.preventDefault();
   209→
   210→        for (const item of imageItems) {
   211→          const file = item.getAsFile();
   212→          if (file) {
   213→            await uploadImage(file);
   214→          }
   215→        }
   216→      }
   217→    };
   218→
   219→    editorElement.addEventListener('dragenter', handleDragEnter);
   220→    editorElement.addEventListener('dragover', handleDragOver);
   221→    editorElement.addEventListener('dragleave', handleDragLeave);
   222→    editorElement.addEventListener('drop', handleDrop);
   223→    editorElement.addEventListener('paste', handlePaste);
   224→
   225→    return () => {
   226→      editorElement.removeEventListener('dragenter', handleDragEnter);
   227→      editorElement.removeEventListener('dragover', handleDragOver);
   228→      editorElement.removeEventListener('dragleave', handleDragLeave);
   229→      editorElement.removeEventListener('drop', handleDrop);
   230→      editorElement.removeEventListener('paste', handlePaste);
   231→    };
   232→  }, [editor, uploadImage]);
   233→
   234→  // Drag overlay
   235→  if (isDragging) {
   236→    return (
   237→      <div className="absolute inset-0 z-50 bg-accent-blue/10 border-2 border-dashed border-accent-blue rounded-lg flex items-center justify-center pointer-events-none">
   238→        <div className="bg-surface-light dark:bg-surface-dark px-6 py-4 rounded-lg shadow-elevated">
   239→          <p className="text-accent-blue text-lg font-semibold">Drop image here</p>
   240→        </div>
   241→      </div>
   242→    );
   243→  }
   244→
   245→  return null;
   246→};
