   357→  const formatHeading = (headingSize: HeadingTagType) => {
   358→    editor.update(() => {
   359→      const selection = $getSelection();
   360→      if ($isRangeSelection(selection)) {
   361→        const anchorNode = selection.anchor.getNode();
   362→        const element = anchorNode.getKey() === 'root'
   363→          ? anchorNode
   364→          : anchorNode.getTopLevelElementOrThrow();
   365→
   366→        if ($isHeadingNode(element) && element.getTag() === headingSize) {
   367→          // If already this heading, convert to paragraph
   368→          const paragraph = $createParagraphNode();
   369→          element.replace(paragraph, true);
   370→        } else {
   371→          // Convert to heading
   372→          const heading = $createHeadingNode(headingSize);
   373→          element.replace(heading, true);
   374→        }
   375→      }
   376→    });
   377→  };
   378→
   379→  const formatParagraph = () => {
   380→    editor.update(() => {
   381→      const selection = $getSelection();
   382→      if ($isRangeSelection(selection)) {
