   565→/**
   566→ * Auto-save Plugin
   567→ * Debounces editor changes and saves to store
   568→ */
   569→const AutoSavePlugin: React.FC<{ noteId: string }> = ({ noteId }) => {
   570→  const [isSaving, setIsSaving] = useState(false);
   571→  const updateNote = useNotesStore((state) => state.updateNote);
   572→
   573→  // Track timeout ID and last saved content to prevent redundant saves
   574→  const timeoutIdRef = useRef<ReturnType<typeof setTimeout> | null>(null);
   575→  const lastContentRef = useRef<string>('');
   576→  const lastTextRef = useRef<string>('');
   577→
   578→  const handleChange = useCallback((editorState: EditorState) => {
   579→    // Extract plain text for search
   580→    editorState.read(() => {
   581→      const root = $getRoot();
   582→      const contentText = root.getTextContent();
   583→      const contentJson = JSON.stringify(editorState.toJSON());
   584→
   585→      // Skip save if content hasn't actually changed
   586→      if (contentJson === lastContentRef.current && contentText === lastTextRef.current) {
   587→        return;
   588→      }
   589→
   590→      // Clear previous timeout to implement proper debouncing
   591→      if (timeoutIdRef.current) {
   592→        clearTimeout(timeoutIdRef.current);
   593→      }
   594→
   595→      // Debounced save with error handling
   596→      timeoutIdRef.current = setTimeout(() => {
   597→        setIsSaving(true);
   598→
   599→        try {
   600→          // Zustand is synchronous, but IndexedDB persistence could fail
   601→          updateNote(noteId, {
   602→            content: contentJson,
   603→            contentText,
   604→          });
   605→
   606→          // Update refs with saved content
   607→          lastContentRef.current = contentJson;
   608→          lastTextRef.current = contentText;
   609→
   610→          // Reset saving state after a brief delay
   611→          setTimeout(() => setIsSaving(false), 300);
   612→        } catch (error) {
   613→          console.error('❌ Failed to save note:', error);
   614→          setIsSaving(false);
   615→          // Error will be handled by IndexedDB quota monitoring system
   616→          // User will be alerted if quota is exceeded via Settings page
   617→        }
   618→      }, NOTE_CONSTANTS.AUTOSAVE_DEBOUNCE_MS);
   619→    });
   620→  }, [noteId, updateNote]);
   621→
   622→  // Cleanup timeout on unmount
   623→  useEffect(() => {
   624→    return () => {
   625→      if (timeoutIdRef.current) {
   626→        clearTimeout(timeoutIdRef.current);
   627→      }
   628→    };
   629→  }, []);
   630→
   631→  return (
   632→    <>
   633→      <OnChangePlugin onChange={handleChange} />
   634→      {isSaving && (
   635→        <div className="absolute top-2 right-2 text-xs text-text-light-secondary dark:text-text-dark-secondary">
   636→          Saving...
   637→        </div>
   638→      )}
   639→    </>
   640→  );
   641→};
