   782→export const NotesEditor: React.FC<NotesEditorProps> = ({ noteId, blockId }) => {
   783→  const note = useNotesStore((state) => state.getNote(noteId));
   784→  const notes = useNotesStore((state) => state.notes);
   785→  const notesArray = useMemo(() => Object.values(notes), [notes]);
   786→  const [wordCount, setWordCount] = useState(0);
   787→  const [charCount, setCharCount] = useState(0);
   788→
   789→  // Memoize editor config to prevent Lexical re-initialization
   790→  // Only recreate when noteId changes, not when content changes
   791→  const editorConfig = useMemo(
   792→    () => getEditorConfig(note?.content),
   793→    [noteId] // Key on noteId only, not note.content
   794→  );
   795→
   796→  const handleWordCountUpdate = useCallback((words: number, chars: number) => {
   797→    setWordCount(words);
   798→    setCharCount(chars);
   799→  }, []);
   800→
   801→  if (!note) {
   802→    return (
   803→      <div className="h-full flex items-center justify-center text-text-light-secondary dark:text-text-dark-secondary">
   804→        Note not found
   805→      </div>
   806→    );
   807→  }
   808→
   809→  return (
   810→    <motion.div
   811→      initial={{ opacity: 0 }}
   812→      animate={{ opacity: 1 }}
   813→      transition={{ duration: 0.2 }}
   814→      className="h-full flex flex-col bg-surface-light dark:bg-surface-dark"
   815→    >
   816→      {/* Note Title & Tags */}
   817→      <div className="border-b border-border-light dark:border-border-dark px-6 py-4 flex-shrink-0">
   818→        <input
   819→          type="text"
   820→          value={note.title}
   821→          onChange={(e) =>
   822→            useNotesStore.getState().updateNote(noteId, { title: e.target.value })
   823→          }
   824→          placeholder="Untitled Note"
   825→          className="w-full text-3xl font-bold bg-transparent border-none outline-none text-text-light-primary dark:text-text-dark-primary placeholder-text-light-secondary dark:placeholder-text-dark-secondary"
   826→        />
   827→        <TagsInput noteId={noteId} tags={note.tags} />
   828→
   829→        {/* Custom Fields (P2 #3) */}
   830→        <NoteCustomFields noteId={noteId} note={note} />
   831→      </div>
   832→
   833→      {/* Lexical Editor */}
   834→      <LexicalComposer key={noteId} initialConfig={editorConfig}>
   835→        <div className="flex-1 flex flex-col relative overflow-hidden shadow-card">
   836→          {/* Toolbar */}
   837→          <div className="flex-shrink-0">
   838→            <EditorToolbar wordCount={wordCount} charCount={charCount} noteId={noteId} />
   839→          </div>
   840→
   841→          {/* Editor Content */}
   842→          <div className="flex-1 overflow-y-auto p-4">
   843→            <div className="relative h-full border border-border-light dark:border-border-dark rounded-lg p-6 bg-surface-light dark:bg-surface-dark">
   844→              <RichTextPlugin
   845→                contentEditable={
   846→                  <ContentEditable className="editor-content outline-none w-full h-full text-text-light-primary dark:text-text-dark-primary text-base" />
   847→                }
   848→                placeholder={
   849→                  <div className="editor-placeholder absolute top-6 left-6 text-text-light-secondary dark:text-text-dark-secondary pointer-events-none opacity-60">
   850→                    Start writing...
   851→                  </div>
   852→                }
   853→                ErrorBoundary={LexicalErrorBoundary}
   854→              />
   855→            <HistoryPlugin />
   856→            <ListPlugin />
   857→            <TablePlugin />
   858→            <MarkdownShortcutPlugin transformers={TRANSFORMERS} />
   859→            <AutoLinkPlugin matchers={MATCHERS} />
   860→            <KeyboardShortcutsPlugin />
   861→            <WordCountPlugin onUpdate={handleWordCountUpdate} />
   862→            <SlashCommandPlugin />
   863→            <ImageUploadPlugin noteId={noteId} />
   864→            <AutoSavePlugin noteId={noteId} />
   865→            <WikiLinkAutocompletePlugin notes={notesArray} currentFolderId={note.folderId} />
   866→            <WikiLinkTransformPlugin notes={notes} />
   867→            <HoverPreviewPlugin notes={notes} />
   868→            <BlockReferencePlugin targetBlockId={blockId} />
   869→            <HashtagPlugin
   870→              onHashtagsChange={(tags) => {
   871→                useNotesStore.getState().updateNote(noteId, { tags });
   872→              }}
   873→            />
   874→            </div>
   875→          </div>
   876→        </div>
   877→      </LexicalComposer>
   878→
   879→      {/* Backlinks Panel */}
   880→      <div className="flex-shrink-0">
   881→        <BacklinksPanel noteId={noteId} />
   882→      </div>
   883→    </motion.div>
   884→  );
   885→};
   886→
   887→/**
   888→ * Empty State - No Note Selected
   889→ */
   890→export const NotesEditorEmpty: React.FC = () => {
   891→  return (
   892→    <div className="h-full flex items-center justify-center bg-surface-light-elevated dark:bg-surface-dark">
   893→      <div className="text-center max-w-md px-8 animate-fade-in">
   894→        <div className="flex justify-center mb-6">
   895→          <div className="p-8 bg-gradient-to-br from-accent-magenta/10 to-accent-cyan/10 dark:from-accent-cyan/10 dark:to-accent-magenta/10 rounded-3xl">
   896→            <div className="text-6xl">📝</div>
   897→          </div>
   898→        </div>
   899→        <h2 className="text-3xl font-bold text-text-light-primary dark:text-text-dark-primary mb-4 tracking-tight">
   900→          Welcome to Notes
   901→        </h2>
   902→        <p className="text-text-light-secondary dark:text-text-dark-secondary mb-4 leading-relaxed">
   903→          Your private space for thoughts, ideas, and knowledge. Everything stays local and secure on your device.
   904→        </p>
   905→        <div className="space-y-2 text-sm text-text-light-tertiary dark:text-text-dark-tertiary">
   906→          <p className="flex items-center justify-center gap-2">
   907→            <kbd className="px-2 py-1 bg-surface-light dark:bg-surface-dark-elevated border border-border-light dark:border-border-dark rounded font-mono text-xs">Cmd+N</kbd>
   908→            Create new note
   909→          </p>
   910→          <p className="flex items-center justify-center gap-2">
   911→            <kbd className="px-2 py-1 bg-surface-light dark:bg-surface-dark-elevated border border-border-light dark:border-border-dark rounded font-mono text-xs">Cmd+K</kbd>
   912→            Search notes
