          {/* Editor Content */}
          <div className="flex-1 overflow-y-auto p-4">
            <div className="relative h-full border border-border-light dark:border-border-dark rounded-lg p-6 bg-surface-light dark:bg-surface-dark">
              <RichTextPlugin
                contentEditable={
                  <ContentEditable className="editor-content outline-none w-full h-full text-text-light-primary dark:text-text-dark-primary text-base" />
                }
